class Solution(object):
    def pickGifts(self, gifts, k):
        import heapq
        heap = [-g for g in gifts]
        heapq.heapify(heap)
        for _ in range(k):
            max_gift = -heapq.heappop(heap)
            new_gift = int(max_gift ** 0.5)
            heapq.heappush(heap, -new_gift)
        return -sum(heap)
